mapper.select:
/*getSkuList*/ SELECT CONCAT(MS.COMPKEY, MS.WAREKEY, MS.OWNERKY, MS.SKUMKEY) as ROWKEY ,MS.COMPKEY, MW.WHNAMLC as WAREKEY, MO.OWNAMLC as OWNERKY, MS.SKUMKEY ,MS.SKUDESC, MS.SKUTYPE, MS.SKUTYPE, MS.CUSKUKY ,MS.CUSKUNM, MS.VDSKUKY, MS.VDSKUNM, MS.SKUSKEY ,MS.SKUSDSC, MS.VENDKEY, MS.PACKKEY, MS.TRUNTYP ,MS.MINIQTY, MS.SALFQTY, MS.SPUTZON, MS.SPUTLOC ,MS.SPIKLOC, MS.VNDFDAY, MS.EANCODE, MS.UPCCODE ,MS.SKUGR01, MS.SKUGR02, MS.SKUGR03, MS.SKUGR04 ,MS.SKUGR05, MS.SKUALT1, MS.SKUALT2, MS.SKUALT3 ,MS.SKUAT01, MS.SKUAT02, MS.SKUAT03, MS.SKUAT04 ,MS.SKUAT05, MS.SGRWEIG, MS.SKULENG, MS.SKULENG ,MS.SKUWIDH, MS.SKUHEIG, MS.SKUCUBI, MS.SUOMKEY ,MS.SKUNOTE, MS.SKUWABC, MS.SKUSTAT, MS.CREDATE ,MS.CRETIME, MS.CREUSER, MS.LMODATE, MS.LMOTIME ,MS.LMOUSER, MS.INDIBZL, MS.INDIARC, MS.UPDTCHK FROM MSKUWC MS LEFT JOIN MWARMA MW ON MS.COMPKEY = MW.COMPKEY AND MS.WAREKEY = MW.WAREKEY LEFT JOIN MOWRMA MO ON MS.COMPKEY = MO.COMPKEY AND MS.OWNERKY = MO.OWNERKY WHERE MS.COMPKEY = #{userData.compkey} AND MS.WAREKEY = #{warekey}
AND UPPER(MS.UPCCODE) = UPPER(#{upccode})
and MS.OWNERKY = #{ownerky}

	/*sp_wm_ctrwrcvit*/
 	CALL sp_wm_ctrwrcvit
	 	(
		  #{userData.compkey}, #{warekey}, #{doctype}, #{rcvdcky}
		  ,fn_wm_rcvdcit(#{userData.compkey},#{rcvdcky}), #{eoasnky}, #{eoasnit}, #{rcveqty}
		  ,#{expidat}, #{rcvrscd}, #{rcvrsnm}, #{userData.useract}
		  ,#{omsgkey, mode=OUT, jdbcType=VARCHAR}
		  ,#{oresult, mode=OUT, jdbcType=INTEGER}
		)

SELECT
	ZONEKEY
FROM
	MLOCMA
WHERE
	COMPKEY = #{userData.compkey}
	AND WAREKEY = #{warekey}
	AND LOCAKEY = #{tolocky}

/*getWrcvitListAsn*/
SELECT concat(WS.COMPKEY, WS.STOCKKY) as ROWKEY , WS.COMPKEY , WS.STOCKKY , '' as LOCANAM , WS.WAREKEY , '' as LOCAKEY , WS.TRUNTYP , WS.TRUNPID , WS.LOTNMKY , WS.OWNERKY , WS.SKUMKEY , WS.SKUDESC , WS.STOTQTY , WS.STOTQTY as FORDQTY , WS.AREAKEY as FRAREKY , WS.ZONEKEY as FRZONKY , WS.LOCAKEY as FRLOCKY , WS.SALLQTY , WS.SINBQTY , WS.SOUBQTY , WS.SBLOQTY , WS.SUOMKEY , MS.SKUWABC , MS.PACKKEY , date_format(WS.PRODDAT, '%Y-%m-%d') as PRODDAT , WS.SHELIFE , WS.EXPIDAT , date_format(WS.RCVDCDT, '%Y-%m-%d') as RCVDCDT , date_format(WS.RCVFRDT, '%Y-%m-%d') as RCVFRDT , WS.LOTFRKY , WS.STKSTAT , WS.RCVDCKY , WS.RCVDCIT , WS.LOTAT01, WS.LOTAT02, WS.LOTAT03, WS.LOTAT04, WS.LOTAT05 , WS.LOTAT06, WS.LOTAT07, WS.LOTAT08, WS.LOTAT09, WS.LOTAT10 , WS.LOTAT11, WS.LOTAT12, WS.LOTAT13, WS.LOTAT14, WS.LOTAT15 , WS.LOTAT16, WS.LOTAT17, WS.LOTAT18, WS.LOTAT19, WS.LOTAT20 , fn_com_todate(WS.CREDATE) as CREDATE, fn_com_totime(WS.CRETIME) as CRETIME, fn_sy_usernam(WS.COMPKEY, WS.CREUSER) as CREUSER , CASE WHEN WS.LMODATE = '' THEN '' ELSE fn_com_todate(WS.LMODATE) END as LMODATE , CASE WHEN WS.LMOTIME = '' THEN '' ELSE fn_com_totime(WS.LMOTIME) END as LMOTIME , fn_sy_usernam(WS.COMPKEY, WS.LMOUSER) as LMOUSER , WS.UPDTCHK , MS.UPCCODE , MO.OWNAMLC as COMBOVL FROM WSTKKY WS INNER JOIN MSKUWC MS ON MS.COMPKEY = WS.COMPKEY AND MS.WAREKEY = WS.WAREKEY AND MS.OWNERKY = WS.OWNERKY AND MS.SKUMKEY = WS.SKUMKEY INNER JOIN MLOCMA ML ON ML.COMPKEY = WS.COMPKEY AND ML.WAREKEY = WS.WAREKEY AND ML.LOCAKEY = WS.LOCAKEY INNER JOIN MOWRMA MO ON MS.COMPKEY = MO.COMPKEY AND MS.OWNERKY = MO.OWNERKY WHERE WS.COMPKEY = #{userData.compkey} AND WS.AREAKEY = 'RCV' AND WS.ZONEKEY = 'RCVZ' AND (WS.STOTQTY-WS.SBLOQTY) > 0 /* 총 수량 */ AND WS.SALLQTY = 0 /* 할당 수량 */ AND WS.SINBQTY = 0 /* 입고중 수량 */ AND WS.SOUBQTY = 0 /* 출고중 수량 */ AND WS.WAREKEY = #{warekey} AND WS.RCVDCKY IN ( SELECT DISTINCT RCVDCKY FROM WRCVIT WHERE EOASNKY = #{eoasnky} )
select concat(WT.COMPKEY, WT.TASKOKY, WT.TASKOIT) as ROWKEY , WT.COMPKEY, WT.TASKOKY, WT.TASKOIT , WT.TASKSTS, WT.WAREKEY, WT.DOCCATE , WT.DOCTYPE , WT.TASKSTS , IFNULL((SELECT DOCTYNM FROM MDOCMA WHERE COMPKEY = WT.COMPKEY AND WAREKEY = WT.WAREKEY AND DOCTYPE = WT.DOCTYPE), WT.DOCTYPE) as DOCTYNM , WT.TRUNTYP , WT.TRUNPID, WT.LOTNMKY, WT.OWNERKY , WT.SKUMKEY, WT.SKUDESC, MS.UPCCODE , WT.VENDKEY , WT.FRAREKY, WT.FRZONKY, WT.FRLOCKY , WT.TOAREKY, WT.TOZONKY, WT.TOLOCKY as LOCAKEY , (SELECT LOCANAM FROM MLOCMA WHERE COMPKEY = WT.COMPKEY AND WAREKEY = WT.WAREKEY AND AREAKEY = WT.TOAREKY AND ZONEKEY = WT.TOZONKY AND LOCAKEY = WT.TOLOCKY) as LOCAKNM , WT.FORDQTY, WT.FUOMEKY, WT.TCMPQTY, WT.TUOMEKY , WT.FORDQTY AS STOTQTY, WS.SALLQTY, WS.SINBQTY, WS.SOUBQTY, WS.SBLOQTY , WT.SIRBCOD, WT.PRODDAT, WT.SHELIFE, WT.EXPIDAT, WT.RCVDCDT, WT.RCVFRDT, WT.LOTFRKY , WT.LOTAT01, WT.LOTAT02, WT.LOTAT03, WT.LOTAT04, WT.LOTAT05, WT.LOTAT06, WT.LOTAT07, WT.LOTAT08, WT.LOTAT09, WT.LOTAT10 , WT.LOTAT11, WT.LOTAT12, WT.LOTAT13, WT.LOTAT14, WT.LOTAT15, WT.LOTAT16, WT.LOTAT17, WT.LOTAT18, WT.LOTAT19, WT.LOTAT20 , WT.STKSTAT , WT.TASKG01, WT.TASKG02, WT.TASKG03, WT.TASKG04, WT.TASKG05 , WT.MOVTEAM, WT.MOVUSID, WT.MVSTDAT, WT.MVSTTIM, WT.MVEDDAT, WT.MVEDTIM, WT.EOASNKY, WT.EOASNIT, WT.RCVDCKY, WT.RCVDCIT, WT.SHPDCKY, WT.SHPDCIT , WT.REFPODC, WT.REFPOIT, WT.REFSODC, WT.REFSOIT, WT.REFDNDC, WT.REFDNIT, WT.REFSDDC, WT.REFSDIT, WT.STORFKY , fn_com_todate(WT.CREDATE) as CREDATE, fn_com_totime(WT.CRETIME) as CRETIME, fn_sy_usernam(WT.COMPKEY, WT.CREUSER) as CREUSER , fn_com_todate(WT.LMODATE) as LMODATE, fn_com_totime(WT.LMOTIME) as LMOTIME, fn_sy_usernam(WT.COMPKEY, WT.LMOUSER) as LMOUSER , WT.INDIBZL, WT.INDIARC, WT.UPDTCHK from WTAKIT WT inner join WRCVIT WR ON WR.RCVDCKY = WT.RCVDCKY AND WR.COMPKEY = WT.COMPKEY AND WR.WAREKEY = WT.WAREKEY AND WR.RCVDCIT = WT.RCVDCIT inner join MSKUWC MS on MS.COMPKEY = WT.COMPKEY and MS.WAREKEY = WT.WAREKEY and MS.OWNERKY = WT.OWNERKY and MS.SKUMKEY = WT.SKUMKEY left join ( select COMPKEY, WAREKEY , AREAKEY, ZONEKEY, LOCAKEY , OWNERKY, SKUMKEY, LOTNMKY , sum(STOTQTY) as STOTQTY, sum(SALLQTY) as SALLQTY , sum(SINBQTY) as SINBQTY, sum(SOUBQTY) as SOUBQTY , sum(SBLOQTY) as SBLOQTY from WSTKKY where COMPKEY = #{userData.compkey}
and WAREKEY = #{warekey}
and (STOTQTY-SBLOQTY) > 0 /* 총 수량 */ and SALLQTY = 0 /* 할당 수량 */ and SINBQTY = 0 /* 입고중 수량 */ and SOUBQTY = 0 /* 출고중 수량 */ group by COMPKEY, WAREKEY, AREAKEY, ZONEKEY, LOCAKEY, OWNERKY, SKUMKEY, LOTNMKY ) WS on WS.COMPKEY = WT.COMPKEY and WS.WAREKEY = WT.WAREKEY and WS.AREAKEY = WT.TOAREKY and WS.ZONEKEY = WT.TOZONKY and WS.LOCAKEY = WT.TOLOCKY and WS.OWNERKY = WT.OWNERKY and WS.SKUMKEY = WT.SKUMKEY and WS.LOTNMKY = WT.LOTNMKY where WT.COMPKEY = #{userData.compkey} and WT.DOCCATE = '500' and WT.DOCTYPE = '510' and WT.TASKSTS = 'TASK' and WT.TOAREKY = 'STG'
and WT.WAREKEY = #{warekey}
and WT.TASKOKY = #{taskoky} order by WT.COMPKEY, WT.TASKOKY, WT.TASKOIT

/* saveWmpTolocky */
 CALL sp_wm_ctrtolocky( #{userData.compkey}, #{warekey}, #{taskoky}, #{doccate}, #{doctype}, #{stockky}
	, #{truntyp}, #{trunpid}, #{fordqty}, #{toareky}, #{tozonky}, #{tolocky}, #{userData.useract}
	, #{omsgkey, mode=OUT, jdbcType=VARCHAR}, #{oresult, mode=OUT, jdbcType=INTEGER} )

mapper.update:
/* updateWtakitWMP50List */
update WTAKIT
set TCMPQTY = #{fordqty}
  ,	 LMODATE = to_char(now() , 'YYYYMMDD')
  ,  LMOTIME = to_char(now() , 'hh24miss')
  ,  LMOUSER = #{userData.useract}
where 1=1
  and COMPKEY = #{userData.compkey}
  and TASKOKY = #{taskoky}
  and TASKOIT = #{taskoit}

mapper.select:
/* updateWtakitList */
CALL sp_wm_ctrstokky( #{userData.compkey}, #{warekey}, #{doccate} , #{doctype}, #{taskoky} , #{taskoit}, #{userData.useract}
	, #{omsgkey, mode=OUT, jdbcType=VARCHAR}, #{oresult, mode=OUT, jdbcType=INTEGER} )

/*getwshpitList*/ select CONCAT(TS.COMPKEY, TS.TASKOKY, TS.TASKOIT) AS ROWKEY , TS.COMPKEY , TS.WAREKEY , TS.OWNERKY , (select OWNAMLC from MOWRMA where COMPKEY = TS.COMPKEY and OWNERKY = TS.OWNERKY ) as OWNAMLC , SH.DCTCTYP , SH.DOCCATE , SH.DOCTYPE , TS.ALLGRKY , SH.SHPDCKY , SH.SHPDCIT , IF(TRIM(TS.COOUTKY) = ' ' , TS.OERETKY , TS.COOUTKY) AS COOUTKY , IF(TRIM(TS.COOUTIT) = 0 , TS.OERETIT , TS.COOUTIT) AS COOUTIT , SH.CUSTKEY , (select CUNAMLC from MCUSMA where COMPKEY = SH.COMPKEY and OWNERKY = SH.OWNERKY and CUSTKEY = SH.CUSTKEY) as CUSTNAM , (SELECT DOCTYNM from MDOCMA where COMPKEY = SH.COMPKEY AND WAREKEY = SH.WAREKEY and DOCCATE = SH.DOCCATE and DOCTYPE = SH.DOCTYPE) as DOCTYNM , TS.TASKSTS , TS.SKUMKEY , TS.SKUDESC , TS.LOTNMKY , (select LOCANAM from MLOCMA where COMPKEY = TS.COMPKEY AND WAREKEY = TS.WAREKEY and LOCAKEY = TS.FRLOCKY) as FRLONAM , TS.FRAREKY , TS.FRZONKY , TS.FRLOCKY , TS.TOAREKY , TS.TOZONKY , TS.TOLOCKY , (select LOCANAM from MLOCMA where COMPKEY = TS.COMPKEY AND WAREKEY = TS.WAREKEY and LOCAKEY = TS.TOLOCKY) as TOLONAM , TS.FORDQTY , TS.FUOMEKY , TS.FORDQTY as TCMPQTY , TS.DIFFQTY , TS.TUOMEKY , TS.SHPDCKY , TS.SHPDCIT , TS.TASKOKY , TS.TASKOIT , TS.TRUNTYP , TS.TRUNPID , TS.OWNERKY , TS.VENDKEY , TS.SIRBCOD , TS.PRODDAT , TS.SHELIFE , TS.EXPIDAT , TS.RCVDCDT , TS.RCVFRDT , TS.LOTFRKY , TS.LOTAT01 , TS.LOTAT02 , TS.LOTAT03 , TS.LOTAT04 , TS.LOTAT05 , TS.LOTAT06 , TS.LOTAT07 , TS.LOTAT08 , TS.LOTAT09 , TS.LOTAT10 , TS.LOTAT11 , TS.LOTAT12 , TS.LOTAT13 , TS.LOTAT14 , TS.LOTAT15 , TS.LOTAT16 , TS.LOTAT17 , TS.LOTAT18 , TS.LOTAT19 , TS.LOTAT20 , TS.STKSTAT , TS.TASKG01 , TS.TASKG02 , TS.TASKG03 , TS.TASKG04 , TS.TASKG05 , TS.PARSNCD , TS.PARSNNM , TS.PKRSNCD , TS.PKRSNNM , TS.MOVTEAM , TS.MOVUSID , TS.MVSTDAT , TS.MVSTTIM , TS.MVEDDAT , TS.MVEDTIM , TS.EOASNKY , TS.EOASNIT , TS.RCVDCKY , TS.RCVDCIT , TS.REFPODC , TS.REFPOIT , TS.REFSODC , TS.REFSOIT , TS.REFDNDC , TS.REFDNIT , TS.REFSDDC , TS.REFSDIT , TS.STORFKY , TS.STKOTKY , TS.STKINKY , TS.UPDTCHK , MS.UPCCODE from WTAKIT TS left join MSKUWC MS on TS.COMPKEY = MS.COMPKEY and TS.WAREKEY = MS.WAREKEY and TS.OWNERKY = MS.OWNERKY and TS.SKUMKEY = MS.SKUMKEY inner join MLOCMA m on TS.COMPKEY = m.COMPKEY and TS.WAREKEY = m.WAREKEY and TS.FRLOCKY = m.LOCAKEY and m.LOCTYPE != 'AUTOSTORE' inner join WSHPIT SH on TS.COMPKEY = SH.COMPKEY and TS.WAREKEY = SH.WAREKEY and TS.OWNERKY = SH.OWNERKY and TS.SHPDCKY = SH.SHPDCKY and TS.SHPDCIT = SH.SHPDCIT where SH.COMPKEY = #{userData.compkey} and SH.WAREKEY = #{warekey} and TS.DOCCATE = '500' and TS.DOCTYPE = '530' and SH.SHPDCST != 'CMP' and TS.TASKSTS = 'TASK'
and TS.ALLGRKY = #{allgrky}
order by TS.COMPKEY, TS.TASKOKY , TS.TASKOIT

/*sp_wm_ctrstokky*/
CALL sp_wm_ctrstokky
(
  #{userData.compkey}
, #{warekey}
, #{doccate}
, #{doctype}
, #{taskoky}
, #{taskoit}
, #{userData.useract}
, #{omsgkey, mode=OUT, jdbcType=VARCHAR}
, #{oresult, mode=OUT, jdbcType=INTEGER}
)

mapper.update:
		/*updateWmp60List*/
		update WTAKIT
    	set
    		  LMODATE = to_char(now(),'YYYYMMDD')
    		, LMOTIME = to_char(now(),'hh24miss')
    		, LMOUSER = #{userData.useract}
    		, TCMPQTY = #{tcmpqty}
    		, DIFFQTY = #{diffqty}
    	where COMPKEY = #{userData.compkey}
    	and TASKOKY = #{taskoky}
    	and TASKOIT = #{taskoit}
    	and UPDTCHK = #{updtchk}

/*updateWmp70List*/
UPDATE WTAKIT
	 SET TCMPQTY = #{fordqty}
	, LMODATE = to_char(now() , 'YYYYMMDD')
	, LMOTIME = to_char(now() , 'hh24miss')
	, LMOUSER = #{userData.useract}
WHERE
	COMPKEY = #{userData.compkey}
	AND TASKOKY = #{taskoky}
	AND TASKOIT = #{taskoit}

mapper.select:
/*updateWmp70ListSp*/
CALL sp_wm_ctrstokky( #{userData.compkey}, #{warekey}, #{doccate} , #{doctype}, #{taskoky} , #{taskoit}, #{userData.useract}
, #{omsgkey, mode=OUT, jdbcType=VARCHAR}, #{oresult, mode=OUT, jdbcType=INTEGER} )

/*getWstkkyList*/ SELECT concat(A.OWNERKY , MAX(A.STOCKKY)) as rowkey , MO.OWNAMLC as ownerky, A.SKUMKEY as skumkey , C.SKUDESC as skudesc , A.WAREKEY as warekey , A.AREAKEY as areakey , A.ZONEKEY as zonekey , A.LOCAKEY as locakey , D.WHNAMLC as whnamlc , SUM(A.STOTQTY) as stotqty , SUM( case when (A.STOTQTY != 0 and A.SALLQTY = 0 and A.SINBQTY = 0 and A.SOUBQTY = 0) then A.STOTQTY - A.SBLOQTY else 0 end) as avalqty , SUM(A.SALLQTY) as sallqty , SUM(A.SINBQTY) as sinbqty , SUM(A.SOUBQTY) as soubqty , SUM(A.SBLOQTY) as sbloqty , A.STKSTAT as stkstat , A.AREAKEY as areakey , A.ZONEKEY as zonekey , A.LOCAKEY as locakey , A.LOTAT01 as lotat01 , A.LOTAT02 as lotat02 , A.LOTAT03 as lotat03 , A.LOTAT04 as lotat04 , A.LOTAT05 as lotat05 , A.LOTAT06 as lotat06 , A.LOTAT07 as lotat07 , A.LOTAT08 as lotat08 , A.LOTAT09 as lotat09 , A.LOTAT10 as lotat10 , A.LOTAT11 as lotat11 , A.LOTAT12 as lotat12 , A.LOTAT13 as lotat13 , A.LOTAT14 as lotat14 , A.LOTAT15 as lotat15 , A.LOTAT16 as lotat16 , A.LOTAT17 as lotat17 , A.LOTAT18 as lotat18 , A.LOTAT19 as lotat19 , A.LOTAT20 as lotat20 , A.LOTNMKY as lotnmky , MA.AREANAM as areanam , MZ.ZONENAM as zonenam , ML.LOCANAM as locanam FROM WSTKKY A INNER JOIN MSKUWC C on A.COMPKEY = C.COMPKEY and A.WAREKEY = C.WAREKEY and A.OWNERKY = C.OWNERKY and A.SKUMKEY = C.SKUMKEY INNER JOIN MWARMA D on A.COMPKEY = D.COMPKEY and A.WAREKEY = D.WAREKEY INNER JOIN MOWRMA MO on A.COMPKEY = MO.COMPKEY and A.OWNERKY = MO.OWNERKY LEFT OUTER JOIN SUSRMA E on A.COMPKEY = E.COMPKEY and C.SKUAT01 = E.USERACT INNER JOIN MAREMA MA on A.COMPKEY = MA.COMPKEY and A.WAREKEY = MA.WAREKEY and A.AREAKEY = MA.AREAKEY INNER JOIN MZONMA MZ on A.COMPKEY = MZ.COMPKEY and A.WAREKEY = MZ.WAREKEY and A.AREAKEY = MZ.AREAKEY and A.ZONEKEY = MZ.ZONEKEY INNER JOIN MLOCMA ML on A.COMPKEY = ML.COMPKEY and A.WAREKEY = ML.WAREKEY and A.AREAKEY = ML.AREAKEY and A.ZONEKEY = ML.ZONEKEY and A.LOCAKEY = ML.LOCAKEY WHERE A.COMPKEY = #{userData.compkey} AND A.STOTQTY != 0 AND A.WAREKEY = #{warekey} AND A.AREAKEY='STG'
AND A.OWNERKY = #{ownerky}
AND UPPER(C.UPCCODE) = UPPER(#{upccode})
AND A.LOCAKEY = #{locakey}
GROUP BY A.OWNERKY, A.WAREKEY, A.SKUMKEY, C.SKUDESC
GROUP BY A.OWNERKY, A.WAREKEY, A.SKUMKEY, C.SKUDESC, A.AREAKEY, A.ZONEKEY, A.LOCAKEY
GROUP BY A.OWNERKY, A.WAREKEY, A.SKUMKEY, C.SKUDESC, A.LOTNMKY, A.AREAKEY, A.ZONEKEY, A.LOCAKEY

/* getWmp91List */ select concat(WT.COMPKEY, WT.TASKOKY, WT.TASKOIT) as ROWKEY , WT.COMPKEY, WT.TASKOKY, WT.TASKOIT , WT.TASKSTS, WT.WAREKEY , WR.DOCTYPE , WT.TRUNTYP , WT.TRUNPID, WT.LOTNMKY, MO.OWNAMLC as OWNERKY , WT.SKUMKEY, WT.SKUDESC , WT.VENDKEY , WT.FRAREKY, WT.FRZONKY, WT.FRLOCKY , WT.TOAREKY, WT.TOZONKY, WT.TOLOCKY , WT.FORDQTY, WT.FUOMEKY, WT.TCMPQTY, WT.TUOMEKY , WS.STOTQTY, WS.SALLQTY, WS.SINBQTY, WS.SOUBQTY, WS.SBLOQTY , WT.SIRBCOD, WT.PRODDAT, WT.SHELIFE, WT.EXPIDAT,fn_com_todate(WT.RCVDCDT), WT.RCVFRDT, WT.LOTFRKY , WT.LOTAT01, WT.LOTAT02, WT.LOTAT03, WT.LOTAT04, WT.LOTAT05, WT.LOTAT06, WT.LOTAT07, WT.LOTAT08, WT.LOTAT09, WT.LOTAT10 , WT.LOTAT11, WT.LOTAT12, WT.LOTAT13, WT.LOTAT14, WT.LOTAT15, WT.LOTAT16, WT.LOTAT17, WT.LOTAT18, WT.LOTAT19, WT.LOTAT20 , WT.STKSTAT , WT.TASKG01, WT.TASKG02, WT.TASKG03, WT.TASKG04, WT.TASKG05 , R1.RSNCDNM as PARSNCD, WT.PARSNNM , WT.MOVTEAM, WT.MOVUSID, WT.MVSTDAT, WT.MVSTTIM, WT.MVEDDAT, WT.MVEDTIM, WT.EOASNKY, WT.EOASNIT, WT.RCVDCKY, WT.RCVDCIT, WT.SHPDCKY, WT.SHPDCIT , WT.REFPODC, WT.REFPOIT, WT.REFSODC, WT.REFSOIT, WT.REFDNDC, WT.REFDNIT, WT.REFSDDC, WT.REFSDIT, WT.STORFKY , fn_com_todate(WT.CREDATE) as CREDATE, fn_com_totime(WT.CRETIME) as CRETIME, fn_sy_usernam(WT.COMPKEY, WT.CREUSER) as CREUSER , fn_com_todate(WT.LMODATE) as LMODATE, fn_com_totime(WT.LMOTIME) as LMOTIME, fn_sy_usernam(WT.COMPKEY, WT.LMOUSER) as LMOUSER , WT.INDIBZL, WT.INDIARC, WT.UPDTCHK , WR.RCHSQTY , WR.RVLOCKY , fn_com_todate(WR.RCVDCDT) as RCVDCDT, fn_com_totime(WR.RCVDCTM) as RCVDCTM , ML.LOCANAM as TOLOCNM , MLO.LOCANAM as RCLOCNM , MCO.COMCDTX as RCVDCNM from WTAKIT WT inner join MSKUWC MS on MS.COMPKEY = WT.COMPKEY and MS.WAREKEY = WT.WAREKEY and MS.OWNERKY = WT.OWNERKY and MS.SKUMKEY = WT.SKUMKEY left join ( select COMPKEY, WAREKEY , AREAKEY, ZONEKEY, LOCAKEY , OWNERKY, SKUMKEY, LOTNMKY , sum(STOTQTY) as STOTQTY, sum(SALLQTY) as SALLQTY , sum(SINBQTY) as SINBQTY, sum(SOUBQTY) as SOUBQTY , sum(SBLOQTY) as SBLOQTY from WSTKKY where COMPKEY = #{userData.compkey} and WAREKEY = #{warekey} and OWNERKY = #{ownerky} and (STOTQTY-SBLOQTY) > 0 /* 총 수량 */ and SALLQTY = 0 /* 할당 수량 */ and SINBQTY = 0 /* 입고중 수량 */ and SOUBQTY = 0 /* 출고중 수량 */ group by COMPKEY, WAREKEY, AREAKEY, ZONEKEY, LOCAKEY, OWNERKY, SKUMKEY, LOTNMKY ) WS on WS.COMPKEY = WT.COMPKEY and WS.WAREKEY = WT.WAREKEY and WS.AREAKEY = WT.TOAREKY and WS.ZONEKEY = WT.TOZONKY and WS.LOCAKEY = WT.TOLOCKY and WS.OWNERKY = WT.OWNERKY and WS.SKUMKEY = WT.SKUMKEY and WS.LOTNMKY = WT.LOTNMKY left join WRCVIT WR on WR.COMPKEY = WT.COMPKEY and WR.WAREKEY = WT.WAREKEY and WR.OWNERKY = WT.OWNERKY and WR.RCVDCKY = WT.RCVDCKY and WR.RCVDCIT = WT.RCVDCIT left join MLOCMA ML on ML.COMPKEY = WT.COMPKEY and ML.WAREKEY = WT.WAREKEY and ML.LOCAKEY = WT.TOLOCKY left join MLOCMA MLO on MLO.COMPKEY = WR.COMPKEY and MLO.WAREKEY = WR.WAREKEY and MLO.LOCAKEY = WR.RVLOCKY left join V_MCODEM MCO on MCO.COMPKEY = WR.COMPKEY and MCO.COMCDKY='RCVDCST' and MCO.COMCDVL = WR.RCVDCST inner join MOWRMA MO on MO.COMPKEY = WT.COMPKEY and MO.OWNERKY = WT.OWNERKY left join MRSCMA R1 on R1.COMPKEY = WT.COMPKEY and R1.WAREKEY = WT.WAREKEY and R1.DOCCATE = WT.DOCCATE and R1.DOCTYPE = WT.DOCTYPE and R1.RSNCODE = WT.PARSNCD left JOIN V_MCODEM MC ON MC.COMPKEY = WT.COMPKEY AND MC.COMCDKY = 'TASKSTS' AND MC.COMCDVL = WT.TASKSTS
where WT.COMPKEY = #{userData.compkey} and WT.DOCCATE = '500' and WT.DOCTYPE IN ('510','520') and WT.TASKSTS = 'TSCOMP' and WT.TOAREKY = 'STG' and WT.WAREKEY = #{warekey} and WT.OWNERKY = #{ownerky}
and WR.RCVDCDT >= replace(#{rcvdcdtfrom}, '-', '')
and WR.RCVDCDT <= replace(#{rcvdcdtto}, '-', '')
and WR.RCVDCDT between replace(#{rcvdcdtfrom}, '-', '') and replace(#{rcvdcdtto}, '-', '')
order by WR.RCVDCDT DESC, WR.RCVDCTM DESC

/* selectWmp91InitList */ select MS.SKUMKEY as combovl , MS.SKUDESC as combonm , MS.COMPKEY , MS.SKUSKEY , MS.WAREKEY as WAREKEY , MS.OWNERKY as OWNERKY , MS.SALFQTY , MS.PROPQTY , case when MS.SKUSTAT = 'OUT' then 'Y' else 'N' end as SKUSTAT , IFNULL(WS.STOTQTY, 0) AS STOTQTY , IFNULL(MS.SUOMKEY, NULL) AS SUOMKEY , MS.PACKKEY as PACKKEY , MS.TRUNTYP as TRUNTYP from MSKUWC MS LEFT OUTER JOIN (select COMPKEY, OWNERKY, WAREKEY , SKUMKEY, SKUDESC , SUM( case when (STOTQTY != 0 and SALLQTY = 0 and SINBQTY = 0 and SOUBQTY = 0) then STOTQTY - SBLOQTY else 0 END) as STOTQTY from WSTKKY where COMPKEY = #{userData.compkey} and AREAKEY IN ('RCV','STG') group by COMPKEY, WAREKEY, OWNERKY, SKUMKEY) WS ON WS.COMPKEY = MS.COMPKEY AND WS.WAREKEY = MS.WAREKEY AND WS.OWNERKY = MS.OWNERKY AND WS.SKUMKEY = MS.SKUMKEY
and MS.COMPKEY = #{userData.compkey}
and MS.WAREKEY = #{warekey}
and MS.OWNERKY = #{ownerky}
group by MS.SKUMKEY, MS.SKUDESC, MS.COMPKEY, MS.SKUSKEY, MS.WAREKEY , MS.OWNERKY, MS.SKUSTAT, WS.STOTQTY, MS.SUOMKEY, MS.PACKKEY , MS.TRUNTYP order by MS.SKUDESC

	/*sp_wm_ctrwrcvit_wmp90*/
 	CALL sp_wm_ctrwrcvit
	 	(
		  #{compkey}, #{warekey}, #{doctype}, #{rcvdcky}
		  ,fn_wm_rcvdcit(#{compkey},#{rcvdcky}), #{eoasnky}, #{eoasnit}, #{rcveqty}
		  ,#{expidat}, #{rcvrscd}, #{rcvrsnm}, 'SYS'
		  ,#{omsgkey, mode=OUT, jdbcType=VARCHAR}
		  ,#{oresult, mode=OUT, jdbcType=INTEGER}
		)

 /* saveWmp90Wasnif */
 CALL sp_wm_ctrwasnif( #{userData.compkey}, #{eoasnky}, #{eoasnit}, #{rcvdcky}, #{rcvdcit}, #{copodky}, #{copodit}
	, #{warekey}, #{doccate}, #{doctype}, #{ownerky}, #{skumkey}, #{rcveqty}, #{asndate}, #{expidat}
	,#{vendkey} , #{rcvrscd}, #{rcvrsnm}, #{userData.useract}
	, #{omsgkey, mode=OUT, jdbcType=VARCHAR}, #{oresult, mode=OUT, jdbcType=INTEGER} )

/*sp_tm_loading*/
CALL sp_tm_loading( #{userData.compkey}, #{warekey}, #{postdat} , #{vhplnky}, #{saatc06} , #{vehicky},
#{eofdtyn}, #{userData.useract}, #{omsgkey, mode=OUT, jdbcType=VARCHAR}, #{oresult, mode=OUT, jdbcType=INTEGER} )

/*sp_tm_plan_loading*/
CALL sp_tm_plan_loading( #{userData.compkey}, #{warekey}, #{postdat} , #{vhplnky}, #{saatc06} , #{vehicky},
#{userData.useract}, #{omsgkey, mode=OUT, jdbcType=VARCHAR}, #{oresult, mode=OUT, jdbcType=INTEGER} )

SELECT 
	VHPLNKY, VHPLNIT
FROM 
	TPLNIT
WHERE
	COMPKEY = #{userData.compkey}
	AND WAREKEY = #{warekey}
	AND VHPLNKY = #{vhplnky}
	AND SAATC06 = #{saatc06}

/* spTmPlanCancelTmp07 */
CALL sp_tm_plan_cancel(
	#{userData.compkey}
	, #{warekey}
	, #{vhplnky}, #{vhplnit}
	, #{userData.useract}
	, #{omsgkey, mode=OUT, jdbcType=VARCHAR}
	, #{oresult, mode=OUT, jdbcType=INTEGER}
	)

{
	/* pdaSpOmOcosalWms */
	CALL SP_OM_OCOSAL_WMS (#{userData.compkey}, #{cooutky}, #{doccate}, #{userData.useract},
	#{omsgkey, mode=OUT, jdbcType=VARCHAR}, #{oresult, mode=OUT, jdbcType=VARCHAR})
}
